+    fn radius_query_returns_sorted_candidate_distances() {
+        // The results should have correct distance values
+        let items = vec![
+            (pt(0.0, 0.0), 1),
+            (pt(1.0, 0.0), 2),
+            (pt(2.0, 0.0), 3),
